 1→import { generateId } from '@/domain/ids';
 2→
 3→export function createSketchProject(name = 'Untitled Sketch') {
 4→  return {
 5→    id: generateId('sketch'),
 6→    name,
 7→    description: '',
 8→    category: 'general',
 9→    canvasWidth: 297000,  // A4 landscape in mm
10→    canvasHeight: 210000,
11→    layers: [createLayer('Layer 1')],
12→    objects: [],
13→    annotations: [],
14→    sheets: [],
15→    createdAt: new Date().toISOString(),
16→    updatedAt: new Date().toISOString(),
17→  };
18→}
19→
20→export function createSketchObject(name = 'Untitled Object', category = 'general') {
21→  return {
22→    id: generateId('sobj'),
23→    name,
24→    category,
25→    description: '',
26→    shapeIds: [],
27→  };
28→}
29→
30→export function createAnnotation(type, props = {}) {
31→  return {
32→    id: generateId('annot'),
33→    type,  // 'dimension', 'label', 'callout'
34→    ...props,
35→  };
36→}
37→
38→export function createLayer(name = 'Layer') {
39→  return {
40→    id: generateId('layer'),
41→    name,
42→    visible: true,
43→    locked: false,
44→    shapes: [],
45→  };
46→}
47→
48→export function createShape(type, props = {}) {
49→  return {
50→    id: generateId('shape'),
51→    type, // 'rect', 'ellipse', 'line', 'path'
52→    layerId: props.layerId || null,
53→    x: props.x ?? 0,
54→    y: props.y ?? 0,
55→    width: props.width ?? 0,
56→    height: props.height ?? 0,
57→    points: props.points ?? [],
58→    fill: props.fill ?? 'none',
59→    stroke: props.stroke ?? '#1E2433',
60→    strokeWidth: props.strokeWidth ?? 2,
61→    rotation: props.rotation ?? 0,
62→  };
63→}
