 80→export default function SketchSidebar() {
 81→  const { project, dispatch, getShapesForObject } = useSketch();
 82→  const { activeLayerId, activeObjectId, dispatch: editorDispatch } = useSketchEditor();
 83→
 84→  const objects = project.objects || [];
 85→
 86→  const handleAddLayer = () => {
 87→    const newLayer = createLayer(`Layer ${project.layers.length + 1}`);
 88→    dispatch({ type: 'LAYER_ADD', layer: newLayer });
 89→    editorDispatch({ type: 'SET_ACTIVE_LAYER', layerId: newLayer.id });
 90→  };
 91→
 92→  const handleSelectLayer = (layerId) => {
 93→    editorDispatch({ type: 'SET_ACTIVE_LAYER', layerId });
 94→  };
 95→
 96→  const handleToggleVisibility = (e, layer) => {
 97→    e.stopPropagation();
 98→    dispatch({
 99→      type: 'LAYER_UPDATE',
100→      layer: { id: layer.id, visible: !layer.visible },
101→    });
102→  };
103→
104→  const handleToggleLock = (e, layer) => {
105→    e.stopPropagation();
106→    dispatch({
107→      type: 'LAYER_UPDATE',
108→      layer: { id: layer.id, locked: !layer.locked },
109→    });
110→  };
111→
112→  const handleAddObject = () => {
113→    const obj = createSketchObject(`Object ${objects.length + 1}`);
114→    dispatch({ type: 'OBJECT_ADD', object: obj });
115→    editorDispatch({ type: 'SET_ACTIVE_OBJECT', objectId: obj.id });
116→  };
117→
118→  const handleSelectObject = (objectId) => {
119→    editorDispatch({
120→      type: 'SET_ACTIVE_OBJECT',
121→      objectId: activeObjectId === objectId ? null : objectId,
122→    });
123→  };
124→
125→  const handleDeleteObject = (e, objectId) => {
126→    e.stopPropagation();
127→    dispatch({ type: 'OBJECT_DELETE', objectId });
128→    if (activeObjectId === objectId) {
129→      editorDispatch({ type: 'SET_ACTIVE_OBJECT', objectId: null });
130→    }
131→  };
132→
133→  const handleDeleteLayer = (e, layerId) => {
134→    e.stopPropagation();
135→    if (project.layers.length <= 1) return;
136→    dispatch({ type: 'LAYER_DELETE', layerId });
137→
138→    // If we're deleting the active layer, switch to the first remaining layer
139→    if (activeLayerId === layerId) {
140→      const remaining = project.layers.find((l) => l.id !== layerId);
141→      if (remaining) {
142→        editorDispatch({ type: 'SET_ACTIVE_LAYER', layerId: remaining.id });
143→      }
144→    }
145→  };
146→
147→  return (
148→    <div className={styles.sidebar}>
149→      {/* Objects panel */}
150→      <div className={styles.section}>
151→        <div className={styles.sectionHeaderRow}>
152→          <span className={styles.sectionTitle}>Objects</span>
153→          <span className={styles.count}>{objects.length}</span>
154→          <button
155→            className={styles.addBtn}
156→            onClick={handleAddObject}
157→            aria-label="Add Object"
158→            title="Add Object"
159→          >
160→            +
161→          </button>
162→        </div>
163→
164→        <div className={styles.layerList}>
165→          {objects.map((obj) => {
166→            const isActive = obj.id === activeObjectId;
167→            const shapeCount = obj.shapeIds.length;
168→
169→            return (
170→              <div
171→                key={obj.id}
172→                className={`${styles.layerItem} ${isActive ? styles.layerItemActive : ''}`}
173→                onClick={() => handleSelectObject(obj.id)}
174→                role="button"
175→                tabIndex={0}
176→                onKeyDown={(e) => {
177→                  if (e.key === 'Enter' || e.key === ' ') {
178→                    e.preventDefault();
179→                    handleSelectObject(obj.id);
180→                  }
181→                }}
182→              >
183→                <div className={styles.layerInfo}>
184→                  <ObjectIcon />
185→                  <span className={styles.layerName}>{obj.name}</span>
186→                  {shapeCount > 0 && (
187→                    <span className={styles.shapeCount}>{shapeCount}</span>
188→                  )}
189→                </div>
190→                <div className={styles.layerActions}>
191→                  <span className={styles.categoryBadge}>{obj.category}</span>
192→                  <button
193→                    className={styles.layerActionBtn}
194→                    onClick={(e) => handleDeleteObject(e, obj.id)}
195→                    aria-label="Delete Object"
196→                    title="Delete Object"
197→                  >
198→                    <TrashIcon />
199→                  </button>
200→                </div>
201→              </div>
202→            );
203→          })}
204→        </div>
205→      </div>
206→
207→      {/* Layers panel */}
208→      <div className={styles.section}>
209→        <div className={styles.sectionHeaderRow}>
210→          <span className={styles.sectionTitle}>Layers</span>
211→          <span className={styles.count}>{project.layers.length}</span>
212→          <button
213→            className={styles.addBtn}
214→            onClick={handleAddLayer}
215→            aria-label="Add Layer"
216→            title="Add Layer"
217→          >
218→            +
219→          </button>
220→        </div>
221→
222→        <div className={styles.layerList}>
223→          {project.layers.map((layer) => {
224→            const isActive = layer.id === activeLayerId;
225→            const shapeCount = layer.shapes.length;
226→
227→            return (
228→              <div
229→                key={layer.id}
230→                className={`${styles.layerItem} ${isActive ? styles.layerItemActive : ''}`}
231→                onClick={() => handleSelectLayer(layer.id)}
232→                role="button"
233→                tabIndex={0}
234→                onKeyDown={(e) => {
235→                  if (e.key === 'Enter' || e.key === ' ') {
236→                    e.preventDefault();
237→                    handleSelectLayer(layer.id);
238→                  }
239→                }}
240→              >
241→                <div className={styles.layerInfo}>
242→                  <span className={styles.layerName}>{layer.name}</span>
243→                  {shapeCount > 0 && (
244→                    <span className={styles.shapeCount}>{shapeCount}</span>
245→                  )}
246→                </div>
247→                <div className={styles.layerActions}>
248→                  <button
249→                    className={styles.layerActionBtn}
250→                    onClick={(e) => handleToggleVisibility(e, layer)}
251→                    aria-label={layer.visible ? 'Hide Layer' : 'Show Layer'}
252→                    title={layer.visible ? 'Hide Layer' : 'Show Layer'}
253→                  >
254→                    <EyeIcon visible={layer.visible} />
255→                  </button>
256→                  <button
257→                    className={styles.layerActionBtn}
258→                    onClick={(e) => handleToggleLock(e, layer)}
259→                    aria-label={layer.locked ? 'Unlock Layer' : 'Lock Layer'}
260→                    title={layer.locked ? 'Unlock Layer' : 'Lock Layer'}
261→                  >
262→                    <LockIcon locked={layer.locked} />
263→                  </button>
264→                  <button
265→                    className={styles.layerActionBtn}
266→                    onClick={(e) => handleDeleteLayer(e, layer.id)}
267→                    disabled={project.layers.length <= 1}
268→                    aria-label="Delete Layer"
269→                    title="Delete Layer"
270→                  >
271→                    <TrashIcon />
272→                  </button>
273→                </div>
274→              </div>
275→            );
276→          })}
277→        </div>
278→      </div>
279→    </div>
280→  );
281→}
